export function circleIconRect(node: Node) {
  let w = node.rect.width / 2;
  let h = node.rect.height / 2;
  if (w > h) {
    w = h;
  } else {
    h = w;
  }
  let top = node.rect.height / 10;
  if (top < 10) {
    top = 10;
  }
  node.iconRect = new Rect(node.rect.x + (node.rect.width - w) / 2, node.rect.y + top, w, h);
}

